package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToListTest : TestBase() {

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        yield() // Give the collector a chance to collect

        job.cancel()
        job.join()

        // The destination list should contain the emitted values
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(acc)
        }

        // Emit some values, including a duplicate
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(2) // duplicate
        sharedFlow.emit(3)

        yield() // Give the collector a chance to collect

        job.cancel()
        job.join()

        // The destination set should contain the emitted values (without duplicates)
        assertEquals(setOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToListWithReplay() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)
        val acc = mutableListOf<Int>()

        // Emit values before subscribing
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        // Emit more values after subscribing
        sharedFlow.emit(3)
        sharedFlow.emit(4)

        yield() // Give the collector a chance to collect

        job.cancel()
        job.join()

        // The destination list should contain all emitted values (including replay)
        assertEquals(listOf(1, 2, 3, 4), acc)
    }
}
"}

